from string_utils.manipulation import prettify

def test_prettify_with_complex_input():
    # Test with an input that contains an email and URL to trigger placeholders
    input_string = 'Contact me at hello@example.com and visit http://example.com for more info.   '
    try:
        output = prettify(input_string)
        print(f"Output: {output}")
        assert isinstance(output, str), "Output should be a string"
    except Exception as e:
        print(f"Error: {e}")

